import{z as e}from"zod";export const GameModeSchema=e.enum(["novel","original"]),GameStatusSchema=e.enum(["active","completed","abandoned"]),TurnRoleSchema=e.enum(["player","narrator","system"]),PlayerStateSchema=e.object({name:e.string().default("\u73A9\u5BB6"),location:e.string().default(""),inventory:e.array(e.string()).default([]),status:e.string().default("\u5065\u5EB7"),relationships:e.record(e.string(),e.string()).default({})}),GameWorldSchema=e.object({mode:GameModeSchema,sourceProjectId:e.string().optional(),title:e.string(),premise:e.string(),setting:e.string(),genre:e.string().default(""),characterSummary:e.string().optional(),worldSummary:e.string().optional(),playerCharacter:e.string(),startingScene:e.string()}),GameTurnSchema=e.object({id:e.string(),role:TurnRoleSchema,content:e.string(),imageUrl:e.string().optional(),audioUrl:e.string().optional(),choices:e.array(e.string()).default([]),timestamp:e.number()}),ScoreDimensionsSchema=e.object({narrative:e.number().min(0).max(100),engagement:e.number().min(0).max(100),creativity:e.number().min(0).max(100),coherence:e.number().min(0).max(100),character:e.number().min(0).max(100),tension:e.number().min(0).max(100)}),AdventureScoreSchema=e.object({totalScore:e.number().min(0).max(100),dimensions:ScoreDimensionsSchema,summary:e.string(),recommendation:e.string(),strengths:e.array(e.string()).default([]),weaknesses:e.array(e.string()).default([]),novelPotential:e.string()}),GameSessionSchema=e.object({id:e.string(),world:GameWorldSchema,player:PlayerStateSchema,turns:e.array(GameTurnSchema).default([]),status:GameStatusSchema.default("active"),createdAt:e.number(),updatedAt:e.number(),turnCount:e.number().default(0),score:AdventureScoreSchema.optional()}),SessionListItemSchema=e.object({id:e.string(),title:e.string(),genre:e.string(),mode:GameModeSchema,status:GameStatusSchema,turnCount:e.number(),createdAt:e.number(),updatedAt:e.number(),hasScore:e.boolean().default(!1),totalScore:e.number().optional()});
